SELECT id, plan_id, order_detail_id, process_status, order_no, line_seq, material_cd, material_nm, product_category, width, height, thickness, unit_type, quantity, area, unit, unit_price, amount, dong, ho, floor, window_type, location_detail, TO_CHAR(delivery_date, 'YYYY-MM-DD') AS delivery_date, remarks FROM hkgn.production_plan_detail WHERE id IN
#{id}
ORDER BY plan_id, line_seq, id
